import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Hotel {
  id: number;
  name: string;
  address: string;
  checkIn: string;
  checkOut: string;
}

export type Step = 'START' | 'HOTEL_SELECTED' | 'DETAIL_VIEW';

export interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: Date;
  type?: 'text' | 'hotel_list' | 'menu_tabs' | 'content_detail';
}

export enum MenuTab {
  INFO = '1',
  FOOD = '2',
  HEALING = '3'
}

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getGeminiResponse = async (userMessage: string, history: { role: 'user' | 'model', parts: { text: string }[] }[]) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.map(h => ({ role: h.role === 'model' ? 'model' as const : 'user' as const, parts: h.parts })),
        { role: 'user', parts: [{ text: userMessage }] }
      ],
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.7,
      },
    });

    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "죄송합니다. 요청을 처리하는 중에 오류가 발생했습니다. 잠시 후 다시 시도해주세요.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Hotel, Message, Step, MenuTab } from './types';
import { HOTELS } from './constants';
import { getGeminiResponse } from './services/geminiService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedHotel, setSelectedHotel] = useState<Hotel | null>(null);
  const [currentStep, setCurrentStep] = useState<Step>('START');

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const addMessage = (role: 'user' | 'assistant', content: string, type: Message['type'] = 'text') => {
    const newMessage: Message = {
      id: Math.random().toString(36).substring(7),
      role,
      content,
      timestamp: new Date(),
      type
    };
    setMessages(prev => [...prev, newMessage]);
  };

  const handleSend = async (text: string = input) => {
    if (!text.trim()) return;

    addMessage('user', text);
    setInput('');
    setIsLoading(true);

    // Context handling based on steps
    const history = messages.map(m => ({
      role: m.role === 'assistant' ? 'model' as const : 'user' as const,
      parts: [{ text: m.content }]
    }));

    const aiResponse = await getGeminiResponse(text, history);
    addMessage('assistant', aiResponse || '답변을 가져오지 못했습니다.');
    setIsLoading(false);

    // Logic to detect hotel selection or menu navigation
    const lowerText = text.toLowerCase();

    // Check if user is starting app
    if (lowerText.includes('앱 시작') || lowerText.includes('안녕')) {
      setCurrentStep('START');
      setSelectedHotel(null);
    }

    // Check if user selected a hotel
    const foundHotel = HOTELS.find(h => text.includes(h.name) || text === h.id.toString());
    if (foundHotel) {
      setSelectedHotel(foundHotel);
      setCurrentStep('HOTEL_SELECTED');
    }

    // Check if user typed "메뉴"
    if (lowerText === '메뉴' && selectedHotel) {
      setCurrentStep('HOTEL_SELECTED');
    }
  };

  const onHotelClick = (hotel: Hotel) => {
    handleSend(hotel.name);
  };

  const onTabClick = (tab: MenuTab) => {
    handleSend(tab);
  };

  return (
    <div className="flex flex-col h-screen max-w-2xl mx-auto bg-white shadow-2xl overflow-hidden font-sans">
      {/* Header */}
      <header className="bg-indigo-700 text-white p-4 flex items-center justify-between shadow-md">
        <div className="flex items-center gap-3">
          <div className="bg-white/20 p-2 rounded-full">
            <i className="fas fa-hotel text-xl"></i>
          </div>
          <div>
            <h1 className="text-xl font-bold">제휴호텔메이트AI</h1>
            <p className="text-xs text-indigo-100">스마트 컨시어지 서비스</p>
          </div>
        </div>
        <button 
          onClick={() => handleSend("앱 시작")}
          className="text-xs bg-indigo-600 hover:bg-indigo-500 px-3 py-1 rounded-full border border-indigo-400 transition"
        >
          초기화
        </button>
      </header>

      {/* Chat Area */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50 scroll-smooth"
      >
        {messages.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-center space-y-6 animate-fade-in">
            <div className="w-24 h-24 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600">
              <i className="fas fa-robot text-4xl"></i>
            </div>
            <div>
              <h2 className="text-2xl font-bold text-gray-800 mb-2">반갑습니다!</h2>
              <p className="text-gray-500 max-w-xs mx-auto">
                편안한 투숙을 도와드리는<br/>제휴호텔메이트AI입니다.
              </p>
            </div>
            <button 
              onClick={() => handleSend("앱 시작")}
              className="bg-indigo-600 text-white px-8 py-3 rounded-full font-bold shadow-lg hover:bg-indigo-700 transition transform hover:scale-105"
            >
              앱 시작하기
            </button>
          </div>
        )}

        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl p-4 shadow-sm ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-white text-gray-800 rounded-tl-none border border-gray-100'
            }`}>
              <div className="whitespace-pre-wrap text-sm leading-relaxed">
                {msg.content}
              </div>
              <div className={`text-[10px] mt-2 opacity-60 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
          </div>
        ))}

        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white border border-gray-100 rounded-2xl p-4 flex gap-2">
              <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></span>
              <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-75"></span>
              <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-150"></span>
            </div>
          </div>
        )}
      </div>

      {/* Action Buttons Overlay */}
      <div className="px-4 pb-2 bg-gray-50">
        {currentStep === 'START' && !isLoading && (
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 mb-2">
            {HOTELS.map(hotel => (
              <button
                key={hotel.id}
                onClick={() => onHotelClick(hotel)}
                className="text-left bg-white p-3 rounded-xl border border-gray-200 hover:border-indigo-400 hover:bg-indigo-50 text-xs font-medium transition shadow-sm flex items-center gap-3"
              >
                <span className="bg-indigo-100 text-indigo-600 w-6 h-6 rounded-full flex items-center justify-center flex-shrink-0">
                  {hotel.id}
                </span>
                <span className="truncate">{hotel.name}</span>
              </button>
            ))}
          </div>
        )}

        {currentStep === 'HOTEL_SELECTED' && !isLoading && selectedHotel && (
          <div className="flex flex-col gap-2 mb-2 animate-slide-up">
            <div className="text-center py-2 px-4 bg-indigo-50 rounded-lg text-xs font-bold text-indigo-700 mb-1 border border-indigo-100">
               🏨 {selectedHotel.name} 메뉴
            </div>
            <div className="grid grid-cols-1 gap-2">
              <button 
                onClick={() => onTabClick(MenuTab.INFO)}
                className="bg-white border border-gray-200 py-3 rounded-xl hover:bg-indigo-600 hover:text-white transition shadow-sm text-sm font-semibold flex items-center justify-center gap-2"
              >
                🏨 호텔 이용 안내 (체크인/아웃)
              </button>
              <button 
                onClick={() => onTabClick(MenuTab.FOOD)}
                className="bg-white border border-gray-200 py-3 rounded-xl hover:bg-indigo-600 hover:text-white transition shadow-sm text-sm font-semibold flex items-center justify-center gap-2"
              >
                🍽️ 주변 맛집 탐방 (10~15곳 추천)
              </button>
              <button 
                onClick={() => onTabClick(MenuTab.HEALING)}
                className="bg-white border border-gray-200 py-3 rounded-xl hover:bg-indigo-600 hover:text-white transition shadow-sm text-sm font-semibold flex items-center justify-center gap-2"
              >
                🌿 힐링 & 산책 코스 (5~10곳 추천)
              </button>
            </div>
          </div>
        )}

        {(messages.length > 0 && !isLoading && currentStep !== 'START' && (
          <div className="flex gap-2 mb-2">
             <button 
              onClick={() => handleSend("메뉴")}
              className="flex-1 bg-white border border-gray-200 py-2 rounded-lg hover:bg-gray-100 transition text-xs font-bold text-gray-600"
            >
              <i className="fas fa-list mr-1"></i> 메뉴로 이동
            </button>
             <button 
              onClick={() => handleSend("앱 시작")}
              className="flex-1 bg-white border border-gray-200 py-2 rounded-lg hover:bg-gray-100 transition text-xs font-bold text-gray-600"
            >
              <i className="fas fa-home mr-1"></i> 처음으로
            </button>
          </div>
        ))}
      </div>

      {/* Input Box */}
      <div className="p-4 bg-white border-t border-gray-100">
        <div className="flex items-center gap-2 bg-gray-100 rounded-full px-4 py-2 border border-gray-200 focus-within:border-indigo-400 focus-within:bg-white transition-all shadow-inner">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="메시지를 입력하세요..."
            className="flex-1 bg-transparent border-none outline-none text-sm py-1"
          />
          <button 
            onClick={() => handleSend()}
            disabled={!input.trim() || isLoading}
            className={`p-2 rounded-full transition ${
              !input.trim() || isLoading ? 'text-gray-400' : 'text-indigo-600 hover:bg-indigo-50'
            }`}
          >
            <i className="fas fa-paper-plane text-lg"></i>
          </button>
        </div>
      </div>

      <style>{`
        @keyframes fade-in {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes slide-up {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
        .animate-fade-in {
          animation: fade-in 0.5s ease-out forwards;
        }
        .animate-slide-up {
          animation: slide-up 0.4s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

export interface Hotel {
  id: number;
  name: string;
  address: string;
  checkIn: string;
  checkOut: string;
}

export type Step = 'START' | 'HOTEL_SELECTED' | 'DETAIL_VIEW';

export interface MessageOption {
  label: string;
  value: string;
  icon?: string;
  link?: string;
}

